"""
mkt-christ commentary — Psalms 34–36
Run: python3 scripts/zc-christ-psalms-34-36.py

Key NT connections:
  Ps34:8   → 1 Pet 2:3 (direct — taste the Lord = taste Christ)
  Ps34:12-16 → 1 Pet 3:10-12 (direct — 5-verse citation block)
  Ps34:20  → John 19:36 (direct — bones not broken at crucifixion)
  Ps35:7,19 → John 15:25 (direct — hated without cause)
  Ps35:11  → Matt 26:59 (direct — false witnesses at Sanhedrin trial)
  Ps35:18  → Heb 2:12 parallel (shadow — great congregation praise)
  Ps36:1   → Rom 3:18 (direct — Paul's universal indictment catena)
  Ps36:9   → John 1:4; 8:12; 4:14 (direct — fountain of life / light)
"""
import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: merge without overwriting any verse already present in existing
    # CHANGE? Do not alter the guard; concurrent agents depend on append-only behavior
    # VERIFY: run twice; second run should report identical byte count for psalms.json
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

NEW_DATA = {"34": {"1": "<p><span class='level'>theme</span> The psalm opens with a vow of unbroken blessing: <em>I will bless the LORD at all times; his praise shall continually be in my mouth.</em> The perfect worshiper who embodies this posture is Christ himself, the Son who eternally blesses the Father. The redeemed share this continuous praise because they are in him (Heb 13:15 — the sacrifice of praise through Christ).</p>", "2": "<p><span class='level'>theme</span> <em>My soul makes its boast in the LORD; let the humble hear and be glad.</em> Paul's theology of boasting grounds in this tradition: <em>Let the one who boasts, boast in the Lord</em> (1 Cor 1:31; 2 Cor 10:17, quoting Jer 9:24). Christ is the one in whom all legitimate boasting is grounded — he is the LORD in whom the soul rightly glories.</p>", "3": "<p><span class='level'>theme</span> <em>Oh, magnify the LORD with me, and let us exalt his name together.</em> The communal invitation to praise is realized in the gathering of the church around the risen Christ. He is the center of the assembly (Matt 18:20), and the congregation's corporate voice magnifies the name he has made known (John 17:26).</p>", "4": "<p><span class='level'>shadow</span> <em>I sought the LORD and he answered me and delivered me from all my fears.</em> In Gethsemane Christ sought the Father with loud cries and tears; Heb 5:7 records that he <em>was heard because of his reverence</em>. The deliverance came not by removing the cup but through resurrection — the ultimate answer to the righteous sufferer's seeking.</p>", "5": "<p><span class='level'>shadow</span> <em>Those who look to him are radiant, and their faces shall never be ashamed.</em> The Transfiguration discloses what looking to Christ produces: his face shone like the sun (Matt 17:2). Paul extends this: beholding the glory of the Lord, believers are <em>transformed into the same image from one degree of glory to another</em> (2 Cor 3:18).</p>", "6": "<p><span class='level'>shadow</span> <em>This poor man cried, and the LORD heard him and saved him out of all his troubles.</em> The poor man who cries is the archetype Christ inhabits: <em>though he was rich, yet for your sake he became poor</em> (2 Cor 8:9). He is the afflicted righteous one whose cry the Father hears — and the resurrection is God's saving answer.</p>", "7": "<p><span class='level'>shadow</span> <em>The angel of the LORD encamps around those who fear him and delivers them.</em> The angel of the LORD in the Hebrew Bible often represents a divine presence that cannot be distinguished from YHWH himself (Gen 16:13; Exod 3:2). Early Christian interpreters read these theophanies as pre-incarnate appearances of the Son — the Deliverer who encamps becomes the one who <em>pitched his tent among us</em> (John 1:14).</p>", "8": "<p><span class='level'>direct</span> <em>Oh, taste and see that the LORD is good! Blessed is the man who takes refuge in him!</em> 1 Pet 2:3 applies this verse directly to Christ: <em>if indeed you have tasted that the Lord is good</em> — addressing newly baptized believers. Peter identifies the LORD of Psalm 34 with the Lord Jesus, making the invitation to taste an invitation to trust Christ himself.</p>", "9": "<p><span class='level'>theme</span> <em>Oh, fear the LORD, you his saints, for those who fear him have no lack!</em> Holy reverence before God is christologically grounded: Christ himself modeled perfect fear of the LORD (Isa 11:2-3; Heb 5:7 — heard because of his reverence), and believers approach the Father with reverence and awe through him (Heb 12:28-29).</p>", "10": "<p><span class='level'>theme</span> <em>The young lions suffer want and hunger, but those who seek the LORD lack no good thing.</em> The bread of life discourse answers this promise directly: <em>I am the bread of life; whoever comes to me shall not hunger, and whoever believes in me shall never thirst</em> (John 6:35). Christ is the one in whom seekers of the LORD find every good thing.</p>", "11": "<p><span class='level'>shadow</span> <em>Come, O children, listen to me; I will teach you the fear of the LORD.</em> The teacher-gathering-children pattern reaches its fulfillment in Christ's invitation: <em>Come to me, all who labor and are heavy laden, and I will give you rest</em> (Matt 11:28-30). He is the divine teacher who gathers children and forms them in the way of the LORD.</p>", "12": "<p><span class='level'>direct</span> <em>What man is there who desires life and loves many days, that he may see good?</em> 1 Pet 3:10-12 quotes Ps 34:12-16 as a block, applying it to Christian conduct under Christ's lordship. Peter's citation transforms the rhetorical question into instruction for the community that belongs to the Lord Jesus.</p>", "13": "<p><span class='level'>direct</span> <em>Keep your tongue from evil and your lips from speaking deceit.</em> Part of the 1 Pet 3:10-12 citation block. Peter addresses this to believers who follow the example of Christ who <em>committed no sin, neither was deceit found in his mouth</em> (1 Pet 2:22, citing Isa 53:9) — the Servant becomes the model the redeemed imitate.</p>", "14": "<p><span class='level'>direct</span> <em>Turn away from evil and do good; seek peace and pursue it.</em> Part of the 1 Pet 3:10-12 citation block. The peace-seeking life is grounded in the one who is our peace (Eph 2:14) — Christ who broke down the wall of hostility becomes the foundation for the pursuit of shalom.</p>", "15": "<p><span class='level'>direct</span> <em>The eyes of the LORD are toward the righteous and his ears toward their cry.</em> Part of the 1 Pet 3:10-12 citation block. The righteous one to whom the LORD's eyes turn is supremely Christ himself — the perfectly righteous man whose cry in Gethsemane and on the cross was heard by the Father (Heb 5:7).</p>", "16": "<p><span class='level'>direct</span> <em>The face of the LORD is against those who do evil, to cut off the memory of them from the earth.</em> Final verse of the 1 Pet 3:10-12 citation block. The judgment the wicked face is administered through Christ to whom all judgment has been given (John 5:22); those who do evil face the one whose face shines in glory (Rev 1:16).</p>", "17": "<p><span class='level'>shadow</span> <em>When the righteous cry for help, the LORD hears and delivers them out of all their troubles.</em> Heb 5:7 applies the pattern to Christ: <em>In the days of his flesh, Jesus offered up prayers and supplications, with loud cries and tears, to him who was able to save him from death, and he was heard.</em> Christ is the righteous one who cries and is delivered — through resurrection.</p>", "18": "<p><span class='level'>revelation of God</span> <em>The LORD is near to the brokenhearted and saves the crushed in spirit.</em> This nearness of God to the crushed is most fully embodied in the Incarnation: God draws near in flesh to weep at Lazarus's tomb (John 11:35), to touch lepers, to receive the broken. Immanuel — God-with-us — is the ultimate answer to the crushed spirit's need.</p>", "19": "<p><span class='level'>shadow</span> <em>Many are the afflictions of the righteous, but the LORD delivers him out of them all.</em> Christ is the afflicted righteous one: <em>he was despised and rejected by men, a man of sorrows and acquainted with grief</em> (Isa 53:3). But the Father delivers him out of them all — the resurrection is the definitive deliverance that validates the pattern promised here.</p>", "20": "<p><span class='level'>direct</span> <em>He keeps all his bones; not one of them is broken.</em> John 19:36 applies this verse directly to the crucifixion: <em>These things took place that the Scripture might be fulfilled: 'Not one of his bones will be broken.'</em> When the soldiers came to break the legs of the crucified, they found Jesus already dead — fulfilling Ps 34:20 to the letter.</p>", "21": "<p><span class='level'>shadow</span> <em>Evil will slay the wicked, and those who hate the righteous will be condemned.</em> The cosmic reversal at the cross and resurrection: sin is condemned in the flesh (Rom 8:3), death is swallowed up in victory (1 Cor 15:54-55), and those who rejected the righteous one face their own condemnation. The evil that struck Christ ultimately destroys only the wicked.</p>", "22": "<p><span class='level'>theme</span> <em>The LORD redeems the life of his servants; none of those who take refuge in him will be condemned.</em> The atonement as redemption: <em>In him we have redemption through his blood, the forgiveness of our trespasses</em> (Eph 1:7). The promise of no condemnation is Paul's great declaration in Rom 8:1 — grounded in what Christ accomplished.</p>"}, "35": {"1": "<p><span class='level'>shadow</span> <em>Contend, O LORD, with those who contend with me; fight against those who fight against me!</em> Christ is the righteous one surrendered to accusers, abandoned to those who contend against him. God's contending on his behalf is the resurrection — the Father fights for the Son by raising him from the dead, vindicating his cause against every accusation (Acts 2:24).</p>", "2": "<p><span class='level'>shadow</span> <em>Take hold of shield and buckler and rise for my help!</em> The call for God to <em>rise</em> for the innocent sufferer anticipates the resurrection itself — God rises to help Christ by raising Christ. The divine warrior imagery (shield and buckler) is fulfilled when God defeats sin and death through the cross (Col 2:15).</p>", "3": "<p><span class='level'>shadow</span> <em>Draw the spear and javelin against my pursuers! Say to my soul, 'I am your salvation!'</em> The word <em>I am your salvation</em> (yeshuatekha — from the root of the name Joshua/Jesus) is spoken by God to the righteous sufferer. Christ's name means precisely this: <em>you shall call his name Jesus, for he will save his people from their sins</em> (Matt 1:21).</p>", "4": "<p><span class='level'>shadow</span> <em>Let them be put to shame and dishonored who seek after my life!</em> Those who sought Christ's life — the chief priests, the crowd, Herod — are ultimately shamed by the resurrection. The one they sought to destroy is declared Lord and Christ (Acts 2:36); the cross that was meant to shame him becomes his throne.</p>", "5": "<p><span class='level'>theme</span> <em>Let them be like chaff before the wind, with the angel of the LORD driving them away!</em> The judgment of the wicked who oppose the righteous is a theme reaching to Christ's parousia: <em>the chaff he will burn with unquenchable fire</em> (Matt 3:12). The one who was driven away by his enemies will himself drive away the chaff at the final harvest.</p>", "6": "<p><span class='level'>shadow</span> <em>Let their way be dark and slippery, with the angel of the LORD pursuing them!</em> Darkness as the path of those who oppose Christ is narratively fulfilled in Judas: <em>he immediately went out. And it was night</em> (John 13:30). The one who betrays the light enters the darkness; the slippery path of treachery leads to destruction.</p>", "7": "<p><span class='level'>direct</span> <em>For without cause they hid their net for me; without cause they dug a pit for my life.</em> Jesus applies the <em>without cause</em> motif of Ps 35:7 and Ps 69:4 to himself: <em>they hated me without a cause</em> (John 15:25). The causeless enmity of David's accusers becomes the pattern Christ identifies as his own — unmotivated hatred that fulfills Scripture.</p>", "8": "<p><span class='level'>shadow</span> <em>Let ruin come upon him when he does not know it, and let the net that he hid ensnare him.</em> The principle of the trapper trapped is fulfilled in the crucifixion-resurrection sequence: those who set the net for Christ are caught in their own schemes. Death itself is destroyed by the death it inflicted; the one cast into the pit becomes the cornerstone (Matt 21:42).</p>", "9": "<p><span class='level'>shadow</span> <em>Then my soul will rejoice in the LORD, exulting in his salvation.</em> The joy of the vindicated righteous one is the joy Christ endured the cross for: <em>who for the joy that was set before him endured the cross, despising the shame</em> (Heb 12:2). The resurrection brings the exulting in salvation that the lament anticipated.</p>", "10": "<p><span class='level'>shadow</span> <em>All my bones shall say, 'O LORD, who is like you, delivering the poor from him who is too strong for him?'</em> The whole body of the righteous sufferer glorifying God anticipates the resurrection body — the body of Christ raised in glory that declares the incomparability of the LORD. Death, stronger than David's enemies, cannot hold the one whose bones speak praise.</p>", "11": "<p><span class='level'>direct</span> <em>Malicious witnesses rise up; they ask me of things I do not know.</em> Matthew 26:59-60 describes the Sanhedrin trial precisely: <em>the chief priests and the whole council were seeking false testimony against Jesus... many false witnesses came forward.</em> The Passion narrative fulfills this verse structurally — malicious witnesses arising against the innocent one.</p>", "12": "<p><span class='level'>shadow</span> <em>They repay me evil for good; my soul is bereft.</em> Christ's betrayal is the supreme instance: Judas repays three years of discipleship and love with a kiss that hands Jesus to his enemies. The crowd repays healings, feedings, and exorcisms with the cry <em>crucify him!</em> — evil repaid for measureless good.</p>", "13": "<p><span class='level'>shadow</span> <em>But I, when they were sick — I wore sackcloth; I afflicted myself with fasting.</em> Christ's compassion for his enemies is revealed at Jerusalem: <em>When he drew near and saw the city, he wept over it</em> (Luke 19:41-44). He mourned over those who would reject him — wearing, as it were, the sackcloth of grief for those who plotted his death.</p>", "14": "<p><span class='level'>shadow</span> <em>I went about as though I grieved for my friend or my brother; I bowed down in mourning, as one who laments his mother.</em> Christ's grief at Lazarus's tomb (John 11:35 — <em>Jesus wept</em>) is the incarnation of this sorrow. He mourns with those who mourn (Rom 12:15), entering fully into human grief even while being the one who overcomes death.</p>", "15": "<p><span class='level'>shadow</span> <em>But at my stumbling they rejoiced and gathered; they gathered against me.</em> The gathering around the cross to mock is the precise fulfillment: <em>those who passed by derided him... so also the chief priests mocked him</em> (Matt 27:39-41). The malicious joy of the crowd at the righteous one's stumbling is the atmosphere of the crucifixion.</p>", "16": "<p><span class='level'>shadow</span> <em>Like profane mockers at a feast, they gnash at me with their teeth.</em> Gnashing teeth at the cross: the rage against Christ as he hangs helpless. The image appears in the Wisdom tradition for frenzied, animal-like hatred. Those who gnash teeth at the crucified Christ will ultimately gnash them in a different context — their own judgment (Matt 8:12).</p>", "17": "<p><span class='level'>shadow</span> <em>How long, O Lord, will you look on? Rescue me from their destruction, my precious life from the lions!</em> The <em>how long</em> of desolation echoes Ps 22:1 (<em>My God, my God, why have you forsaken me?</em>) — the Passion cry. Christ's experience of divine absence on the cross is the supreme instance of this lament's depth, and the resurrection is God's answer to <em>how long.</em></p>", "18": "<p><span class='level'>direct</span> <em>I will give you thanks in the great congregation; in the mighty throng I will praise you.</em> Heb 2:12 quotes Ps 22:22 but the structure here anticipates the same movement — the vindicated sufferer leading praise among the congregation. Christ leads his brothers in praise within the assembly (Heb 2:12), the great congregation of the redeemed.</p>", "19": "<p><span class='level'>direct</span> <em>Let not those rejoice over me who are wrongfully my foes, and let not those wink the eye who hate me without cause.</em> John 15:25 cites <em>they hated me without cause</em> — the exact phrase shared by Ps 35:19 and Ps 69:4. Jesus applies it directly to himself: <em>But the word that is written in their Law must be fulfilled: 'They hated me without a cause.'</em></p>", "20": "<p><span class='level'>shadow</span> <em>For they do not speak peace, but against those who are quiet in the land they devise words of deceit.</em> The plotting of the Sanhedrin against the peaceful Christ: <em>the chief priests and the scribes were seeking how to put him to death</em> (Luke 22:2). Against the Prince of Peace they devise deception — Judas's betrayal is the culmination of words of deceit.</p>", "21": "<p><span class='level'>shadow</span> <em>They open wide their mouths against me; they say, 'Aha, Aha! Our eyes have seen it!'</em> The verbal assault at the trial and cross: the high priest tearing his robes and declaring blasphemy (Matt 26:65), the crowd's taunts (<em>aha, you who would destroy the temple!</em>, Mark 15:29-30). Mouths opened wide against the Servant of the LORD (Isa 53:7 — <em>he opened not his mouth</em>, in contrast).</p>", "22": "<p><span class='level'>shadow</span> <em>You have seen, O LORD; be not silent! O Lord, be not far from me!</em> The silence of God at the cross — <em>My God, my God, why have you forsaken me?</em> — breaks at the resurrection. God who was not silent raised Jesus from the dead (Acts 2:24). The prayer <em>be not far from me</em> is answered by the Spirit's indwelling of the risen body of believers.</p>", "23": "<p><span class='level'>shadow</span> <em>Awake and rouse yourself for my vindication, for my cause, my God and my Lord!</em> The call to God to <em>awake</em> anticipates resurrection language: <em>Awake, O sleeper, and arise from the dead, and Christ will shine on you</em> (Eph 5:14). The Father's rousing of himself for the Son's vindication is the resurrection — God declared Jesus to be his Son in power (Rom 1:4).</p>", "24": "<p><span class='level'>shadow</span> <em>Vindicate me, O LORD my God, according to your righteousness, and let them not rejoice over me!</em> God vindicates the Son's righteousness through resurrection: Christ <em>was declared to be the Son of God in power according to the Spirit of holiness by his resurrection from the dead</em> (Rom 1:4). The Father's verdict of righteousness silences those who rejoiced at the cross.</p>", "25": "<p><span class='level'>shadow</span> <em>Let them not say in their hearts, 'Aha, our heart's desire!' Let them not say, 'We have swallowed him up.'</em> The gloating that Christ is swallowed up by death is overturned by resurrection. Death swallowed him — but he swallows up death in victory (1 Cor 15:54). The enemy's claim to have consumed the righteous one is permanently reversed at the empty tomb.</p>", "26": "<p><span class='level'>shadow</span> <em>Let them be put to shame and confused altogether who rejoice at my calamity!</em> The eschatological reversal: at the Name of Jesus every knee will bow (Phil 2:10-11) — those who rejoiced at his calamity will confess his Lordship. The shame they intended for the cross rebounds on themselves at the parousia.</p>", "27": "<p><span class='level'>shadow</span> <em>Let those who delight in my righteousness shout for joy and be glad and say evermore, 'Great is the LORD, who delights in the welfare of his servant!'</em> The shout of joy over Christ's righteousness is the church's cry: those clothed in his imputed righteousness (Phil 3:9) shout evermore as they behold the welfare of the vindicated Servant of the LORD.</p>", "28": "<p><span class='level'>shadow</span> <em>Then my tongue will tell of your righteousness and of your praise all the day long.</em> The risen Christ's proclamation parallels Heb 2:12 (from Ps 22:22): the vindicated sufferer tells of God's righteousness to his brothers. The day-long praise is realized in the church's liturgy — Christ himself leads the praise of his Father through the gathered assembly.</p>"}, "36": {"1": "<p><span class='level'>direct</span> <em>Transgression speaks to the wicked deep in his heart; there is no fear of God before his eyes.</em> Paul quotes this verse in Romans 3:18 as the climax of his catena of OT passages proving universal sin: <em>'There is no fear of God before their eyes.'</em> The conclusion of Rom 3:10-18 sets up the need for Christ's justifying work — no one is exempt from this indictment, which is why Christ must be the righteousness of God for all who believe.</p>", "2": "<p><span class='level'>theme</span> <em>For he flatters himself in his own eyes that his iniquity cannot be found out and hated.</em> Self-deception is the universal condition from which Christ liberates: humanity <em>became futile in their thinking, and their foolish hearts were darkened</em> (Rom 1:21). The renewal of the mind Christ brings (Rom 12:2) is the cure for self-flattering blindness.</p>", "3": "<p><span class='level'>theme</span> <em>The words of his mouth are trouble and deceit; he has ceased to act wisely and do good.</em> This anatomy of verbal sin connects to Paul's portrait of universal corruption (Rom 3:13-14 similarly catalogs mouth-sins). Christ bears this indictment in the atonement — he who had no deceit in his mouth (1 Pet 2:22; Isa 53:9) bore the deceit of others.</p>", "4": "<p><span class='level'>shadow</span> <em>He plots trouble while on his bed; he sets himself in a way that is not good; he does not reject evil.</em> The anatomy of sin becomes the frame for understanding those who plotted against Christ: <em>the chief priests and elders of the people gathered in the palace of the high priest and plotted together to arrest Jesus by stealth and kill him</em> (Matt 26:3-4). Bedside plotting against the righteous one.</p>", "5": "<p><span class='level'>revelation of God</span> <em>Your steadfast love, O LORD, extends to the heavens; your faithfulness to the clouds.</em> The cosmic chesed that spans the heavens finds its supreme revelation in the Incarnation and atonement: God's love is <em>great</em> — <em>even when we were dead in our trespasses, [he] made us alive together with Christ</em> (Eph 2:4-5). The love that reaches the heavens stooped to earth.</p>", "6": "<p><span class='level'>revelation of God</span> <em>Your righteousness is like the mountains of God; your judgments are like the great deep.</em> The righteousness of God, firm as mountains and fathomless as the deep, is <em>the righteousness of God through faith in Jesus Christ for all who believe</em> (Rom 3:21-22). The mountain-firm righteousness becomes gift — imputed to the ungodly in Christ.</p>", "7": "<p><span class='level'>revelation of God</span> <em>How precious is your steadfast love, O God! The children of mankind take refuge in the shadow of your wings.</em> The shadow of God's wings as refuge reaches its incarnate expression when Christ laments: <em>How often would I have gathered your children together as a hen gathers her brood under her wings, and you were not willing!</em> (Matt 23:37). The shadow of God's wings becomes the shadow of the cross.</p>", "8": "<p><span class='level'>shadow</span> <em>They feast on the abundance of your house, and you give them drink from the river of your delights.</em> The eucharistic feast anticipation: Christ feeds the redeemed from the abundance of God's house (John 6:35 — <em>whoever comes to me shall not hunger</em>). The river of delights is the living water Christ gives (John 4:14; Rev 22:1 — the river of the water of life).</p>", "9": "<p><span class='level'>direct</span> <em>For with you is the fountain of life; in your light do we see light.</em> This verse is a proto-Johannine confession that John explicitly develops. <em>In him was life, and the life was the light of men</em> (John 1:4) — life and light united in Christ. <em>I am the light of the world</em> (John 8:12). <em>The water I give him will become in him a spring of water welling up to eternal life</em> (John 4:14). Christ is the fountain; Christ is the light.</p>", "10": "<p><span class='level'>theme</span> <em>Oh, continue your steadfast love to those who know you, and your righteousness to the upright of heart!</em> The prayer for persevering love is answered in the unchanging Christ: <em>Jesus Christ is the same yesterday and today and forever</em> (Heb 13:8). He who loved his own to the end (John 13:1) continues his steadfast love through the intercession of the risen Lord (Rom 8:34).</p>", "11": "<p><span class='level'>shadow</span> <em>Let not the foot of arrogance come upon me, nor the hand of the wicked drive me away.</em> Those who trample underfoot the Son of God face the severest judgment (Heb 10:29 — <em>how much worse punishment will be deserved by the one who has trampled underfoot the Son of God</em>). The righteous sufferer's prayer against being trampled is answered by Christ's exaltation above all rule and authority (Eph 1:21).</p>", "12": "<p><span class='level'>shadow</span> <em>There the evildoers lie fallen; they are thrust down, unable to rise.</em> The proleptic defeat of all who oppose Christ — the Book of Revelation's vision of the final overthrow: <em>the beast was captured, and with it the false prophet</em> (Rev 19:20). Those who were unable to fall before the cross find themselves unable to rise at the judgment of the one who was himself raised.</p>"}}

if __name__ == '__main__':
    book = 'psalms'
    source = 'mkt-christ'
    existing = load_comm(source, book)
    merge_comm(existing, NEW_DATA)
    save_comm(source, book, existing)
    for ch, vv in NEW_DATA.items():
        saved = existing.get(ch, {})
        missing = [v for v in vv if v not in saved]
        print(f'  ch {ch}: {len(vv)} entries, {len(missing)} missing after merge')
